import json
import re
from typing import Any, Optional


def parse_partial_json(s: str) -> Optional[Any]:
    """
    Parse a JSON string that may be missing closing braces or have other issues.

    This is extremely useful for LLM outputs that might be truncated or malformed.

    Args:
        s: The JSON string to parse (can be incomplete)

    Returns:
        The parsed JSON object, or None if unable to parse

    Examples:
        >>> parse_partial_json('{"name": "file_read", "args": {"file_path')
        {"name": "file_read", "args": {"file_path": ""}}

        >>> parse_partial_json('{"tool": "file_search"')
        {"tool": "file_search"}
    """
    # Attempt to parse the string as-is
    try:
        return json.loads(s)
    except json.JSONDecodeError:
        pass

    # Initialize variables for smart parsing
    new_chars = []
    stack = []  # Track open braces/brackets
    is_inside_string = False
    escaped = False

    # Process each character one at a time
    for char in s:
        new_char = char
        if is_inside_string:
            if char == '"' and not escaped:
                is_inside_string = False
            elif char == "\n" and not escaped:
                # Replace unescaped newlines with escape sequence
                new_char = "\\n"
            elif char == "\\":
                escaped = not escaped
            else:
                escaped = False
        elif char == '"':
            is_inside_string = True
            escaped = False
        elif char == "{":
            stack.append("}")
        elif char == "[":
            stack.append("]")
        elif char in {"}", "]"}:
            if stack and stack[-1] == char:
                stack.pop()
            else:
                # Mismatched closing character - malformed input
                return None

        new_chars.append(new_char)

    # Close any unclosed string
    if is_inside_string:
        if escaped:
            new_chars.pop()  # Remove unterminated escape
        new_chars.append('"')

    # Reverse stack to get closing characters in correct order
    stack.reverse()

    # Try progressively removing characters until we can parse
    while new_chars:
        try:
            # Try to parse with auto-added closing braces
            return json.loads("".join(new_chars + stack))
        except json.JSONDecodeError:
            # Remove last character and try again
            new_chars.pop()

    # Complete failure - return None instead of raising
    return None


def parse_json_from_markdown(text: str) -> Optional[dict]:
    """
    Extract and parse JSON from markdown code blocks.

    Handles cases where models wrap JSON in ```json``` blocks.

    Args:
        text: Text that may contain JSON in markdown code blocks

    Returns:
        Parsed JSON dict, or None if unable to parse

    Examples:
        >>> parse_json_from_markdown('```json\\n{"tool": "file_read"}\\n```')
        {"tool": "file_read"}

        >>> parse_json_from_markdown('Here is the result:\\n{"success": true}')
        {"success": true}
    """
    # First try direct parsing
    try:
        return json.loads(text.strip())
    except json.JSONDecodeError:
        pass

    # Try to find JSON within triple backticks
    markdown_pattern = re.compile(r"```(?:json)?(.*?)```", re.DOTALL)
    match = markdown_pattern.search(text)

    if match:
        json_str = match.group(1).strip()
    else:
        # No markdown block - treat entire text as potential JSON
        json_str = text.strip()

    # Strip common wrapper characters
    json_str = json_str.strip(" \n\r\t`")

    # Handle newlines and special characters inside strings
    # Models often output unescaped newlines in string values
    json_str = _fix_newlines_in_strings(json_str)

    # Try parsing with our partial parser
    return parse_partial_json(json_str)


def _fix_newlines_in_strings(text: str) -> str:
    """
    Fix unescaped newlines within JSON string values.

    LLMs often output strings with literal newlines instead of \\n.
    This function finds those and escapes them properly.
    """
    def replace_newlines(match: re.Match[str]) -> str:
        """Replace newlines in matched string value"""
        prefix = match.group(1)  # The key and opening quote
        value = match.group(2)   # The string value
        suffix = match.group(3)  # The closing quote

        # Escape special characters
        value = re.sub(r"\n", r"\\n", value)
        value = re.sub(r"\r", r"\\r", value)
        value = re.sub(r"\t", r"\\t", value)
        value = re.sub(r'(?<!\\)"', r'\"', value)  # Escape unescaped quotes

        return prefix + value + suffix

    # Pattern to match string values in JSON
    # This is a simplified version - matches most common cases
    pattern = r'("(?:[^"]+)"\s*:\s*")(.*?)(")'
    return re.sub(pattern, replace_newlines, text, flags=re.DOTALL)


def smart_json_parse(text: str, expected_keys: Optional[list] = None) -> Optional[dict]:
    """
    The ultimate JSON parser - tries everything to extract valid JSON.

    Combines all strategies:
    1. Standard json.loads()
    2. Markdown extraction
    3. Partial JSON parsing (auto-close braces)
    4. Newline fixing

    Args:
        text: Text that may contain JSON
        expected_keys: Optional list of keys that must be present

    Returns:
        Parsed JSON dict, or None if unable to parse
        IMPORTANT: Only returns dict or None, never strings/lists/primitives

    Examples:
        >>> smart_json_parse('{"name": "file_read"')  # Missing closing brace
        {"name": "file_read"}

        >>> smart_json_parse('```\\n{"tool": "search"}\\n```')  # Markdown
        {"tool": "search"}
    """
    # Try markdown extraction first (handles code blocks)
    result = parse_json_from_markdown(text)

    if result is None:
        return None

    # CRITICAL FIX: Enforce contract - only return dict or None
    # If the parsed result is not a dict (e.g., string, list, number), reject it
    if not isinstance(result, dict):
        return None

    # Validate expected keys if provided
    if expected_keys:
        for key in expected_keys:
            if key not in result:
                return None

    return result


# For backwards compatibility with LangChain naming
parse_json_markdown = parse_json_from_markdown


# ============================================================================
# ENHANCEMENT 1: Chain/Array Detection
# ============================================================================

def is_tool_chain_array(parsed: Any) -> bool:
    """
    Check if parsed result is an array of tool calls (tool chain).

    Args:
        parsed: Parsed JSON result

    Returns:
        True if it's a tool chain array, False otherwise

    Examples:
        >>> is_tool_chain_array([{"name": "file_search"}, {"name": "file_read"}])
        True

        >>> is_tool_chain_array({"name": "file_search"})
        False

        >>> is_tool_chain_array([{"name": "only_one"}])
        False  # Need at least 2 for a chain
    """
    if not isinstance(parsed, list):
        return False

    if len(parsed) < 2:  # Need at least 2 tools to be a chain
        return False

    # Check all items are dicts with "name" field
    return all(
        isinstance(item, dict) and "name" in item
        for item in parsed
    )


def detect_format_type(parsed: Any) -> str:
    """
    Detect what type of structure the parsed JSON represents.

    Args:
        parsed: Parsed JSON result

    Returns:
        One of: "tool_chain", "single_tool", "unknown"

    Examples:
        >>> detect_format_type([{"name": "tool1"}, {"name": "tool2"}])
        "tool_chain"

        >>> detect_format_type({"name": "file_read", "args": {}})
        "single_tool"
    """
    if is_tool_chain_array(parsed):
        return "tool_chain"

    if isinstance(parsed, dict):
        # Check for single tool patterns
        if "name" in parsed:
            return "single_tool"
        if parsed.get("type") == "tool_call" and "name" in parsed:
            return "single_tool"

    return "unknown"


# ============================================================================
# ENHANCEMENT 2: Tool Name Validation
# ============================================================================

def validate_tool_name(tool_name: str, known_tools: set) -> bool:
    """
    Check if tool name exists in the set of known tools.

    Args:
        tool_name: Name of the tool to validate
        known_tools: Set of valid tool names

    Returns:
        True if valid, False otherwise
    """
    return tool_name in known_tools


def validate_tool_call(parsed: dict, known_tools: set) -> tuple[bool, Optional[str]]:
    """
    Validate that a parsed tool call uses valid tool names.

    Args:
        parsed: Parsed JSON (can be dict or list)
        known_tools: Set of valid tool names

    Returns:
        Tuple of (is_valid, error_message)

    Examples:
        >>> validate_tool_call({"name": "file_read"}, {"file_read", "file_write"})
        (True, None)

        >>> validate_tool_call({"name": "fake_tool"}, {"file_read"})
        (False, "Unknown tool: fake_tool")
    """
    if isinstance(parsed, dict):
        # Single tool
        tool_name = parsed.get("name")
        if not tool_name:
            return False, "No 'name' field found"

        if tool_name not in known_tools:
            return False, f"Unknown tool: {tool_name}"

        return True, None

    elif isinstance(parsed, list):
        # Tool chain
        for i, item in enumerate(parsed):
            if not isinstance(item, dict):
                return False, f"Chain item {i+1} is not a dict"

            tool_name = item.get("name")
            if not tool_name:
                return False, f"Chain item {i+1} missing 'name' field"

            if tool_name not in known_tools:
                return False, f"Unknown tool in chain at position {i+1}: {tool_name}"

        return True, None

    return False, "Parsed result is neither dict nor list"


# ============================================================================
# ENHANCEMENT 3: Error Context
# ============================================================================

def smart_json_parse_with_context(
    text: str,
    expected_keys: Optional[list] = None,
    known_tools: Optional[set] = None
) -> tuple[Optional[Any], Optional[str], dict]:
    """
    Parse JSON with full error context and metadata.

    Args:
        text: Text to parse
        expected_keys: Optional list of required keys
        known_tools: Optional set of valid tool names

    Returns:
        Tuple of (parsed_result, error_message, metadata)

    Metadata includes:
        - format_type: "tool_chain" | "single_tool" | "unknown"
        - validation_passed: bool
        - parsing_strategy: "direct" | "markdown" | "partial" | "failed"

    Examples:
        >>> result, error, meta = smart_json_parse_with_context('{"name": "file_read"')
        >>> print(meta)
        {'format_type': 'single_tool', 'validation_passed': True, 'parsing_strategy': 'partial'}
    """
    metadata = {
        "format_type": "unknown",
        "validation_passed": False,
        "parsing_strategy": "failed"
    }

    # Try parsing
    parsed = None
    error = None

    # Strategy 1: Direct parsing
    try:
        parsed = json.loads(text.strip())
        metadata["parsing_strategy"] = "direct"
    except json.JSONDecodeError:
        pass

    # Strategy 2: Markdown extraction
    if parsed is None:
        parsed = parse_json_from_markdown(text)
        if parsed:
            metadata["parsing_strategy"] = "markdown"

    # No result yet - parsing failed
    if parsed is None:
        error = "Could not parse text as JSON (tried direct, markdown, and partial parsing)"
        return None, error, metadata

    # Detect format type
    metadata["format_type"] = detect_format_type(parsed)

    # Validate expected keys
    if expected_keys and isinstance(parsed, dict):
        missing_keys = [k for k in expected_keys if k not in parsed]
        if missing_keys:
            error = f"Missing required keys: {', '.join(missing_keys)}"
            return None, error, metadata

    # Validate tool names
    if known_tools:
        is_valid, validation_error = validate_tool_call(parsed, known_tools)
        metadata["validation_passed"] = is_valid

        if not is_valid:
            error = validation_error
            return None, error, metadata

    metadata["validation_passed"] = True
    return parsed, None, metadata


# ============================================================================
# ENHANCEMENT 4: Python Function Format Support
# ============================================================================

def parse_python_function_call(text: str) -> Optional[dict]:
    """
    Parse Python function call format: tool_name(arg1="value1", arg2="value2")

    Args:
        text: Text containing Python function call

    Returns:
        Parsed dict with {"name": "tool_name", "args": {...}} or None

    Examples:
        >>> parse_python_function_call('file_read(file_path="test.txt")')
        {"name": "file_read", "args": {"file_path": "test.txt"}}

        >>> parse_python_function_call('web_search(query="python tutorial", max_results="10")')
        {"name": "web_search", "args": {"query": "python tutorial", "max_results": "10"}}
    """
    # Pattern: function_name(arg="value", ...)
    func_pattern = re.compile(r'(\w+)\s*\(([^)]*)\)', re.MULTILINE)
    match = func_pattern.search(text)

    if not match:
        return None

    func_name = match.group(1)
    args_str = match.group(2)

    # Parse arguments
    args = {}
    if args_str.strip():
        # Pattern for key="value" or key='value'
        arg_pattern = re.compile(r'(\w+)\s*=\s*["\']([^"\']*)["\']')
        for arg_match in arg_pattern.finditer(args_str):
            key = arg_match.group(1)
            value = arg_match.group(2)
            args[key] = value

    return {
        "name": func_name,
        "args": args
    }


# ============================================================================
# ENHANCEMENT 5: Typo Correction / Tool Suggestion
# ============================================================================

def suggest_similar_tool(invalid_name: str, known_tools: set, cutoff: float = 0.6) -> Optional[str]:
    """
    Suggest closest matching tool name using edit distance.

    Args:
        invalid_name: The invalid tool name
        known_tools: Set of valid tool names
        cutoff: Minimum similarity ratio (0.0 to 1.0)

    Returns:
        Suggested tool name or None

    Examples:
        >>> suggest_similar_tool("file_raed", {"file_read", "file_write"})
        "file_read"

        >>> suggest_similar_tool("websearch", {"web_search", "file_search"})
        "web_search"
    """
    from difflib import get_close_matches

    matches = get_close_matches(invalid_name, list(known_tools), n=1, cutoff=cutoff)
    return matches[0] if matches else None


def smart_json_parse_with_validation(
    text: str,
    known_tools: Optional[set] = None,
    expected_keys: Optional[list] = None,
    suggest_fixes: bool = True
) -> tuple[Optional[Any], Optional[str], Optional[str]]:
    """
    Parse JSON with validation and helpful error messages/suggestions.

    Args:
        text: Text to parse
        known_tools: Set of valid tool names
        expected_keys: List of required keys
        suggest_fixes: Whether to suggest corrections for errors

    Returns:
        Tuple of (parsed_result, error_message, suggestion)

    Examples:
        >>> result, error, suggestion = smart_json_parse_with_validation(
        ...     '{"name": "file_raed"}',
        ...     known_tools={"file_read", "file_write"}
        ... )
        >>> print(suggestion)
        "Did you mean 'file_read'?"
    """
    parsed, error, metadata = smart_json_parse_with_context(text, expected_keys, known_tools)

    suggestion = None

    # If validation failed due to unknown tool, suggest similar tools
    if error and "Unknown tool" in error and known_tools and suggest_fixes:
        # Extract the invalid tool name from error message
        if ":" in error:
            invalid_tool = error.split(":")[-1].strip()
            similar = suggest_similar_tool(invalid_tool, known_tools)
            if similar:
                suggestion = f"Did you mean '{similar}'?"

    return parsed, error, suggestion


if __name__ == "__main__":
    # Test cases for basic parsing
    print("=" * 70)
    print("BASIC JSON PARSING TESTS")
    print("=" * 70 + "\n")

    test_cases = [
        # Incomplete JSON
        '{"name": "file_read", "args": {"file_path": "test.txt"',

        # Markdown wrapped
        '```json\n{"tool": "file_search", "pattern": "*.py"}\n```',

        # Missing closing braces
        '[{"name": "file_search"}, {"name": "file_read"',

        # Unescaped newlines
        '{"content": "line1\nline2\nline3"}',

        # Mixed issues
        '```\n{"name": "test", "value": "has\nnewlines"',
    ]

    for i, test in enumerate(test_cases, 1):
        print(f"{i}. Input: {test[:60]}...")
        result = smart_json_parse(test)
        print(f"   Result: {result}\n")

    # Test chain detection
    print("\n" + "=" * 70)
    print("CHAIN DETECTION TESTS")
    print("=" * 70 + "\n")

    chain_tests = [
        '[{"name": "file_search", "arguments": {"pattern": "*.txt"}}, {"name": "file_read", "arguments": {"file_path": "test.txt"}}]',
        '{"name": "file_read", "args": {}}',  # Single tool
        '[{"name": "only_one"}]',  # Not a chain (only 1 tool)
    ]

    for i, test in enumerate(chain_tests, 1):
        parsed = smart_json_parse(test)
        is_chain = is_tool_chain_array(parsed)
        format_type = detect_format_type(parsed)
        print(f"{i}. Is chain: {is_chain}, Format: {format_type}")
        print(f"   Input: {test[:60]}...\n")

    # Test validation
    print("\n" + "=" * 70)
    print("VALIDATION TESTS")
    print("=" * 70 + "\n")

    known_tools = {"file_read", "file_write", "file_search", "web_search"}

    validation_tests = [
        '{"name": "file_read", "args": {}}',  # Valid
        '{"name": "fake_tool", "args": {}}',  # Invalid
        '[{"name": "file_search"}, {"name": "file_read"}]',  # Valid chain
        '[{"name": "file_search"}, {"name": "fake_tool"}]',  # Invalid chain
    ]

    for i, test in enumerate(validation_tests, 1):
        result, error, suggestion = smart_json_parse_with_validation(test, known_tools=known_tools)
        print(f"{i}. Valid: {error is None}")
        if error:
            print(f"   Error: {error}")
        if suggestion:
            print(f"   Suggestion: {suggestion}")
        print(f"   Input: {test[:60]}...\n")

    # Test Python function parsing
    print("\n" + "=" * 70)
    print("PYTHON FUNCTION FORMAT TESTS")
    print("=" * 70 + "\n")

    python_tests = [
        'file_read(file_path="test.txt")',
        'web_search(query="python tutorial", max_results="10")',
        'file_search(pattern="*.py", path="/home/user")',
    ]

    for i, test in enumerate(python_tests, 1):
        result = parse_python_function_call(test)
        print(f"{i}. Input: {test}")
        print(f"   Result: {result}\n")

    # Test typo correction
    print("\n" + "=" * 70)
    print("TYPO CORRECTION TESTS")
    print("=" * 70 + "\n")

    typo_tests = [
        ("file_raed", known_tools),
        ("websearch", known_tools),
        ("read_file", known_tools),
        ("completely_wrong", known_tools),
    ]

    for i, (typo, tools) in enumerate(typo_tests, 1):
        suggestion = suggest_similar_tool(typo, tools)
        print(f"{i}. Typo: '{typo}' → Suggestion: '{suggestion}'")
